// 2022-01-18 - DFCT0010759 - "TaskerUtils" script include is generating errors 
// Script Continued Below

// STRY0081883 - DFCT0010759
// var Utils = new TaskerUtils();

try{
	//RJ TEMPLATE PERMISSIONS UPDATE
	var allow = false;
	// STRY0081883 - deleting schedules is controlled by the users who can run them, not the users who can edit the templates
	var userInfoScripts =  new UserInfoScripts();
	var grTemp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
	// STRY0141844 - new method to separate who can run permissions from run permissions
	if(grTemp.get(current.getValue('tasker_process')))
		allow = userInfoScripts.userHasRunTemplatePermissions(grTemp);
	answer = allow;
}catch(e) {


	// DFCT0010759 - eventually, this should change to a real utility called from everywhere for consitency.  
	//               For now, this util was only used 2 times so, backing it out.
	// var context = "Tasker | x_153465_discovert_tasker_schedule.delete";
	// Utils.Catch(context, e);

	gs.error(gs.getMessage("Tasker | ") + gs.getMessage("x_153465_discovert_tasker_schedule.delete") + ": " + e.message + 
			gs.getMessage('LineNumber : ') + e.lineNumber + 
			gs.getMessage('SourceName : ') + e.sourceName +
			gs.getMessage('Name: ') + e.name + gs.getMessage('Message : ') + e.message);		

		answer = false;
	}
